/**
 * @name OS Command Injection via Runtime.exec or ProcessBuilder
 * @description User-controlled input flows to OS command execution
 * @kind path-problem
 * @problem.severity error
 * @id java/os-command-injection-nifi
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module OsCommandInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Runtime.exec(String) - shell interpreted
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // ProcessBuilder constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ProcessBuilder.command(...)
    exists(MethodCall mc |
      mc.getMethod().hasName("command") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module OsCommandInjectionFlow = TaintTracking::Global<OsCommandInjectionConfig>;
import OsCommandInjectionFlow::PathGraph

from OsCommandInjectionFlow::PathNode source, OsCommandInjectionFlow::PathNode sink
where OsCommandInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential OS command injection from $@.", source.getNode(), "user-controlled input"

/**
 * @name HTTP request body/parameter to OS command injection
 * @description Verify HTTP request body, path parameters and query parameters flowing to command execution
 * @kind path-problem
 * @problem.severity error
 * @id java/http-to-command-injection-comprehensive
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module HttpCommandConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // ProcessBuilder constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ProcessBuilder.command()
    exists(MethodCall mc |
      mc.getMethod().hasName("command") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Runtime.exec()
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // List.add() in command building context
    exists(MethodCall mc |
      mc.getMethod().hasName("add") and
      (
        mc.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("%ShellUserGroupProvider%") or
        mc.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("%NssShellCommands%") or
        mc.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("%OsxShellCommands%") or
        mc.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("%RemoteShellCommands%")
      ) and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module HttpCommandFlow = TaintTracking::Global<HttpCommandConfig>;
import HttpCommandFlow::PathGraph

from HttpCommandFlow::PathNode source, HttpCommandFlow::PathNode sink
where HttpCommandFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTTP request input flows to OS command from $@.", source.getNode(), "HTTP input"

/**
 * @name ExecuteProcess and ExecuteStreamCommand - flowfile attribute injection into command
 * @description FlowFile attributes or processor properties flow into OS command construction
 * @kind path-problem
 * @problem.severity error
 * @id java/execute-process-command-injection
 * @tags security
 *       external/cwe/cwe-078
 *       external/cwe/cwe-088
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module ExecuteProcessConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // FlowFile attribute access (potential user-controlled data)
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getAttribute") or
        mc.getMethod().hasName("getAttributes") or
        mc.getMethod().hasName("evaluate") or
        mc.getMethod().hasName("getValue")
      ) and
      (
        mc.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("%ExecuteProcess%") or
        mc.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("%ExecuteStreamCommand%")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ProcessBuilder constructor with list
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ProcessBuilder.command(...)
    exists(MethodCall mc |
      mc.getMethod().hasName("command") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Runtime.exec()
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // List.add() calls that build command lists
    exists(MethodCall mc |
      mc.getMethod().hasName("add") and
      (
        mc.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("%ExecuteProcess%") or
        mc.getEnclosingCallable().getDeclaringType().getQualifiedName().matches("%ExecuteStreamCommand%")
      ) and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ExecuteProcessFlow = TaintTracking::Global<ExecuteProcessConfig>;
import ExecuteProcessFlow::PathGraph

from ExecuteProcessFlow::PathNode source, ExecuteProcessFlow::PathNode sink
where ExecuteProcessFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "FlowFile attribute or evaluated expression flows to command execution from $@.", source.getNode(), "attribute/expression"
